{
  "name": "OmniCX AI - Customer Experience Management",
  "description": "An industry-inspired omnichannel support dashboard featuring rule-based and Gemini AI-driven ticket tagging, prioritization, and response suggestions."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Channel {
  EMAIL = 'Email',
  CHAT = 'Chat',
  WEB_FORM = 'Web Form',
  TWITTER = 'Twitter'
}

export enum Priority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  URGENT = 'Urgent'
}

export enum Status {
  OPEN = 'Open',
  IN_PROGRESS = 'In Progress',
  RESOLVED = 'Resolved'
}

export enum Category {
  BILLING = 'Billing',
  TECHNICAL = 'Technical Support',
  ACCOUNT = 'Account Access',
  FEEDBACK = 'General Feedback',
  SALES = 'Sales Inquiry'
}

export interface Ticket {
  id: string;
  customerName: string;
  customerEmail: string;
  channel: Channel;
  category: Category;
  priority: Priority;
  status: Status;
  subject: string;
  message: string;
  tags: string[];
  suggestedResponse?: string;
  createdAt: string;
  updatedAt: string;
}

export interface AnalyticsData {
  totalTickets: number;
  statusDistribution: { name: string; value: number }[];
  channelDistribution: { name: string; value: number }[];
  priorityDistribution: { name: string; value: number }[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { RULE_TAGS } from "../constants";
import { Priority, Category, Ticket } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Pure rule-based processing (Student/Interview Level)
 */
export const processTicketWithRules = (message: string) => {
  const lowerMessage = message.toLowerCase();
  const foundTags: string[] = [];
  let suggestedPriority = Priority.MEDIUM;

  // Rule-based tagging
  Object.keys(RULE_TAGS).forEach(keyword => {
    if (lowerMessage.includes(keyword)) {
      foundTags.push(...RULE_TAGS[keyword]);
    }
  });

  // Rule-based prioritization
  if (lowerMessage.includes('urgent') || lowerMessage.includes('broken') || lowerMessage.includes('critical')) {
    suggestedPriority = Priority.URGENT;
  } else if (lowerMessage.includes('refund') || lowerMessage.includes('billing')) {
    suggestedPriority = Priority.HIGH;
  }

  return {
    tags: Array.from(new Set(foundTags)),
    priority: suggestedPriority
  };
};

/**
 * Gemini AI Enhanced processing (Advanced/Industry Level)
 */
export const getAISuggestions = async (ticket: Partial<Ticket>) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this customer support ticket and suggest a professional response, 
      correct category, and a summary.

      Customer Name: ${ticket.customerName}
      Subject: ${ticket.subject}
      Message: ${ticket.message}

      Provide your response in JSON format.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestedResponse: { type: Type.STRING },
            suggestedCategory: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["suggestedResponse", "suggestedCategory", "summary"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result;
  } catch (error) {
    console.error("AI Service Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Ticket, Channel, Status, Priority, Category } from './types';
import { INITIAL_TICKETS } from './constants';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import TicketForm from './components/TicketForm';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Analytics from './components/Analytics';
import TicketDetail from './components/TicketDetail';

type View = 'landing' | 'dashboard' | 'form' | 'analytics' | 'ticket-detail';

const App: React.FC = () => {
  const [view, setView] = useState<View>('landing');
  const [tickets, setTickets] = useState<Ticket[]>(() => {
    const saved = localStorage.getItem('omnicx_tickets');
    return saved ? JSON.parse(saved) : INITIAL_TICKETS;
  });
  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('omnicx_tickets', JSON.stringify(tickets));
  }, [tickets]);

  const addTicket = (newTicket: Ticket) => {
    setTickets(prev => [newTicket, ...prev]);
    setView('dashboard');
  };

  const updateTicket = (id: string, updates: Partial<Ticket>) => {
    setTickets(prev => prev.map(t => t.id === id ? { ...t, ...updates, updatedAt: new Date().toISOString() } : t));
  };

  const deleteTicket = (id: string) => {
    setTickets(prev => prev.filter(t => t.id !== id));
  };

  const selectedTicket = useMemo(() => 
    tickets.find(t => t.id === selectedTicketId) || null
  , [tickets, selectedTicketId]);

  const handleTicketClick = (id: string) => {
    setSelectedTicketId(id);
    setView('ticket-detail');
  };

  const renderContent = () => {
    switch (view) {
      case 'landing':
        return <LandingPage onGetStarted={() => setView('dashboard')} />;
      case 'dashboard':
        return (
          <Dashboard 
            tickets={tickets} 
            onTicketClick={handleTicketClick} 
            onAddRequest={() => setView('form')}
          />
        );
      case 'form':
        return <TicketForm onSubmit={addTicket} onCancel={() => setView('dashboard')} />;
      case 'analytics':
        return <Analytics tickets={tickets} />;
      case 'ticket-detail':
        return selectedTicket ? (
          <TicketDetail 
            ticket={selectedTicket} 
            onUpdate={updateTicket} 
            onDelete={deleteTicket}
            onBack={() => setView('dashboard')} 
          />
        ) : <Dashboard tickets={tickets} onTicketClick={handleTicketClick} onAddRequest={() => setView('form')} />;
      default:
        return <LandingPage onGetStarted={() => setView('dashboard')} />;
    }
  };

  if (view === 'landing') {
    return <LandingPage onGetStarted={() => setView('dashboard')} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar currentView={view} onViewChange={(v) => setView(v as View)} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header onNewTicket={() => setView('form')} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';

