export default Sidebar;

import React, { useState, useMemo } from 'react';
import { Ticket, Channel, Priority, Status } from '../types';

interface DashboardProps {
  tickets: Ticket[];
  onTicketClick: (id: string) => void;
  onAddRequest: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ tickets, onTicketClick, onAddRequest }) => {
  const [filter, setFilter] = useState({
    status: 'All',
    priority: 'All',
    channel: 'All'
  });

  const filteredTickets = useMemo(() => {
    return tickets.filter(t => {
      const statusMatch = filter.status === 'All' || t.status === filter.status;
      const priorityMatch = filter.priority === 'All' || t.priority === filter.priority;
      const channelMatch = filter.channel === 'All' || t.channel === filter.channel;
      return statusMatch && priorityMatch && channelMatch;
    });
  }, [tickets, filter]);

  const stats = useMemo(() => ({
    total: tickets.length,
    open: tickets.filter(t => t.status === Status.OPEN).length,
    urgent: tickets.filter(t => t.priority === Priority.URGENT).length,
    resolved: tickets.filter(t => t.status === Status.RESOLVED).length
  }), [tickets]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Ticket Queue</h1>
          <p className="text-slate-500">Managing {filteredTickets.length} active queries</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <select 
            value={filter.status}
            onChange={(e) => setFilter({...filter, status: e.target.value})}
            className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500"
          >
            <option>All Status</option>
            {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          <select 
            value={filter.priority}
            onChange={(e) => setFilter({...filter, priority: e.target.value})}
            className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500"
          >
            <option>All Priority</option>
            {Object.values(Priority).map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard label="Total Tickets" value={stats.total} icon="fa-list-check" color="blue" />
        <StatCard label="Open Tickets" value={stats.open} icon="fa-folder-open" color="orange" />
        <StatCard label="Urgent" value={stats.urgent} icon="fa-bolt" color="red" />
        <StatCard label="Resolved" value={stats.resolved} icon="fa-circle-check" color="green" />
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-500 text-xs font-bold uppercase tracking-wider">
                <th className="px-6 py-4">Ticket Info</th>
                <th className="px-6 py-4">Customer</th>
                <th className="px-6 py-4">Channel</th>
                <th className="px-6 py-4">Priority</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Created</th>
                <th className="px-6 py-4 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTickets.map(ticket => (
                <tr 
                  key={ticket.id} 
                  className="hover:bg-slate-50 cursor-pointer transition-colors"
                  onClick={() => onTicketClick(ticket.id)}
                >
                  <td className="px-6 py-4">
                    <p className="text-sm font-bold text-slate-900">{ticket.subject}</p>
                    <div className="flex gap-1 mt-1">
                      {ticket.tags.slice(0, 2).map(tag => (
                        <span key={tag} className="text-[10px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded-full uppercase font-bold">{tag}</span>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm text-slate-800">{ticket.customerName}</p>
                    <p className="text-xs text-slate-400">{ticket.customerEmail}</p>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <ChannelIcon channel={ticket.channel} />
                      <span className="text-sm text-slate-600">{ticket.channel}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <PriorityBadge priority={ticket.priority} />
                  </td>
                  <td className="px-6 py-4">
                    <StatusBadge status={ticket.status} />
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">
                    {new Date(ticket.createdAt).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="text-indigo-600 hover:text-indigo-800 font-bold text-xs uppercase tracking-widest">
                      Manage
                    </button>
                  </td>
                </tr>
              ))}
              {filteredTickets.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center">
                    <div className="flex flex-col items-center gap-4">
                      <i className="fas fa-search text-slate-200 text-5xl"></i>
                      <p className="text-slate-400 font-medium">No tickets found matching your filters</p>
                      <button 
                        onClick={onAddRequest}
                        className="text-indigo-600 font-bold underline"
                      >
                        Create a new ticket
                      </button>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: number; icon: string; color: string }> = ({ label, value, icon, color }) => {
  const colorMap: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-600',
    orange: 'bg-orange-50 text-orange-600',
    red: 'bg-red-50 text-red-600',
    green: 'bg-green-50 text-green-600',
  };
  return (
    <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-slate-500">{label}</p>
        <p className="text-2xl font-bold text-slate-900 mt-1">{value}</p>
      </div>
      <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl ${colorMap[color]}`}>
        <i className={`fas ${icon}`}></i>
      </div>
    </div>
  );
};

export const ChannelIcon: React.FC<{ channel: Channel }> = ({ channel }) => {
  switch (channel) {
    case Channel.EMAIL: return <i className="fas fa-envelope text-blue-500"></i>;
    case Channel.CHAT: return <i className="fas fa-comment-dots text-green-500"></i>;
    case Channel.WEB_FORM: return <i className="fas fa-globe text-purple-500"></i>;
    case Channel.TWITTER: return <i className="fab fa-twitter text-sky-400"></i>;
    default: return <i className="fas fa-circle-question"></i>;
  }
};

export const PriorityBadge: React.FC<{ priority: Priority }> = ({ priority }) => {
  const styles = {
    [Priority.LOW]: 'bg-slate-100 text-slate-600',
    [Priority.MEDIUM]: 'bg-blue-50 text-blue-600',
    [Priority.HIGH]: 'bg-orange-50 text-orange-600',
    [Priority.URGENT]: 'bg-red-100 text-red-700 font-extrabold ring-1 ring-red-200 animate-pulse',
  };
  return <span className={`text-[10px] uppercase tracking-wider font-bold px-2 py-1 rounded-md ${styles[priority]}`}>{priority}</span>;
};

export const StatusBadge: React.FC<{ status: Status }> = ({ status }) => {
  const styles = {
    [Status.OPEN]: 'bg-indigo-50 text-indigo-700',
    [Status.IN_PROGRESS]: 'bg-amber-50 text-amber-700',
    [Status.RESOLVED]: 'bg-emerald-50 text-emerald-700',
  };
  return (
    <span className={`flex items-center gap-1.5 text-xs font-semibold px-2.5 py-1 rounded-full ${styles[status]}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${status === Status.RESOLVED ? 'bg-emerald-500' : 'bg-current'}`}></span>
      {status}
    </span>
  );
};

export default Dashboard;

