import React, { useState, useEffect } from 'react';
import { Ticket, Status, Priority, Category } from '../types';
import { StatusBadge, PriorityBadge, ChannelIcon } from './Dashboard';
import { getAISuggestions } from '../services/aiService';

interface TicketDetailProps {
  ticket: Ticket;
  onUpdate: (id: string, updates: Partial<Ticket>) => void;
  onDelete: (id: string) => void;
  onBack: () => void;
}

const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, onUpdate, onDelete, onBack }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<{ suggestedResponse: string; summary: string } | null>(null);
  const [replyText, setReplyText] = useState('');

  useEffect(() => {
    const fetchAI = async () => {
      setIsAiLoading(true);
      const suggestions = await getAISuggestions(ticket);
      if (suggestions) {
        setAiAnalysis({
          suggestedResponse: suggestions.suggestedResponse,
          summary: suggestions.summary
        });
      }
      setIsAiLoading(false);
    };

    if (ticket.message.length > 20) {
      fetchAI();
    }
  }, [ticket.id]);

  const handleStatusChange = (newStatus: Status) => {
    onUpdate(ticket.id, { status: newStatus });
  };

  const useSuggestedReply = () => {
    if (aiAnalysis) setReplyText(aiAnalysis.suggestedResponse);
  };

  const handleSendReply = () => {
    alert(`Reply sent to ${ticket.customerEmail}`);
    handleStatusChange(Status.RESOLVED);
    onBack();
