export const SLABadge: React.FC<{ deadline: string, priority: Priority, status: Status }> = ({ deadline, priority, status }) => {
  if (status === Status.RESOLVED) return <span className="text-[9px] text-emerald-600 font-bold uppercase"><i className="fas fa-check-double mr-1"></i> SLA Met</span>;

  const now = new Date();
  const target = new Date(deadline);
  const diff = target.getTime() - now.getTime();
  const isBreaching = diff < 3600000; // Less than 1 hour

  if (diff < 0) return <span className="text-[9px] text-rose-600 font-bold uppercase animate-pulse"><i className="fas fa-warning mr-1"></i> Breached</span>;

  return (
    <span className={`text-[9px] font-bold uppercase flex items-center gap-1 ${isBreaching ? 'text-amber-600' : 'text-slate-400'}`}>
      <i className="fas fa-clock text-[8px]"></i>
      {Math.floor(diff / 3600000)}h left
    </span>
  );
};

