    'Positive': { icon: 'fa-face-smile', color: 'text-emerald-500', bg: 'bg-emerald-50' },
    'Neutral': { icon: 'fa-face-meh', color: 'text-slate-400', bg: 'bg-slate-50' },
    'Frustrated': { icon: 'fa-face-frown', color: 'text-amber-500', bg: 'bg-amber-50' },
    'Critical': { icon: 'fa-face-angry', color: 'text-rose-500', bg: 'bg-rose-50' },
  };

  const current = sentiment ? map[sentiment] : map['Neutral'];

  return (
    <div className={`inline-flex items-center gap-2 px-2 py-1 rounded-lg ${current.bg} border border-slate-100`}>
      <i className={`fas ${current.icon} ${current.color}`}></i>
      <span className={`text-[10px] font-bold uppercase ${current.color}`}>{sentiment || 'Analysing...'}</span>
    </div>
  );
};

export const ChannelIcon: React.FC<{ channel: Channel }> = ({ channel }) => {
  switch (channel) {
