import React, { useState, useEffect } from 'react';
import { Ticket, Status, Priority, Category, Sentiment } from '../types';
import { StatusBadge, PriorityBadge, ChannelIcon, SentimentIcon } from './Dashboard';
import { getAISuggestions } from '../services/aiService';

interface TicketDetailProps {
  ticket: Ticket;
  onUpdate: (id: string, updates: Partial<Ticket>) => void;
  onDelete: (id: string) => void;
  onBack: () => void;
}

const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, onUpdate, onDelete, onBack }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<{ suggestedResponse: string; summary: string; sentiment: Sentiment; kbKeywords: string[] } | null>(null);
  const [replyText, setReplyText] = useState('');

  useEffect(() => {
    const fetchAI = async () => {
      setIsAiLoading(true);
      const suggestions = await getAISuggestions(ticket);
      if (suggestions) {
        setAiAnalysis({
          suggestedResponse: suggestions.suggestedResponse,
          summary: suggestions.summary,
          sentiment: suggestions.sentiment as Sentiment,
          kbKeywords: suggestions.kbKeywords || []
        });
        if (suggestions.sentiment && !ticket.sentiment) {
          onUpdate(ticket.id, { sentiment: suggestions.sentiment as Sentiment });
        }
      }
      setIsAiLoading(false);
    };

    if (ticket.message.length > 5) {
      fetchAI();
    }
  }, [ticket.id]);

  const handleStatusChange = (newStatus: Status) => {
    const newHistory = [
      ...ticket.history,
      { id: Date.now().toString(), action: `Status changed to ${newStatus}`, timestamp: new Date().toISOString(), user: 'Alex Agent' }
    ];
    onUpdate(ticket.id, { status: newStatus, history: newHistory });
  };

  const useSuggestedReply = () => {
    if (aiAnalysis) setReplyText(aiAnalysis.suggestedResponse);
  };

  const handleSendReply = () => {
    const newHistory = [
      ...ticket.history,
      { id: Date.now().toString(), action: `Reply sent: "${replyText.substring(0, 30)}..."`, timestamp: new Date().toISOString(), user: 'Alex Agent' }
    ];
    onUpdate(ticket.id, { status: Status.RESOLVED, history: newHistory });
    alert(`Reply dispatched via ${ticket.channel}`);
    onBack();
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all border border-slate-100">
            <i className="fas fa-arrow-left"></i>
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900">{ticket.subject}</h2>
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{ticket.id}</span>
              <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(ticket.createdAt).toLocaleString()}</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <SentimentIcon sentiment={ticket.sentiment || aiAnalysis?.sentiment} />
          <StatusBadge status={ticket.status} />
          <button 
            onClick={() => onDelete(ticket.id)}
            className="w-10 h-10 rounded-xl text-slate-300 hover:text-rose-500 hover:bg-rose-50 flex items-center justify-center transition-all"
          >
            <i className="fas fa-trash-can"></i>
          </button>
        </div>
      </div>

      <div className="grid lg:grid-cols-12 gap-6">
        {/* Left Column: Conversation & Reply */}
        <div className="lg:col-span-8 space-y-6">
          <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full min-h-[500px]">
            <div className="p-8 flex-1">
              <div className="flex items-start gap-4 mb-8">
                <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold shadow-inner">
                  {ticket.customerName.charAt(0)}
                </div>
                <div className="flex-1 bg-slate-50 border border-slate-100 p-6 rounded-2xl rounded-tl-none relative shadow-sm">
                  <div className="flex justify-between mb-2">
                    <span className="text-xs font-bold text-slate-900">{ticket.customerName} <span className="text-slate-400 font-medium ml-2">&lt;{ticket.customerEmail}&gt;</span></span>
                    <ChannelIcon channel={ticket.channel} />
                  </div>
                  <p className="text-slate-700 leading-relaxed text-sm">{ticket.message}</p>
                </div>
              </div>

              {/* Response Editor */}
              <div className="mt-auto border-t border-slate-100 pt-8">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Drafting Enterprise Response</h3>
                  {aiAnalysis && (
                    <button 
                      onClick={useSuggestedReply}
                      className="bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg border border-indigo-100 hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                    >
                      <i className="fas fa-magic mr-2"></i> Use Suggestion
                    </button>
                  )}
                </div>
                <div className="relative">
                  <textarea 
                    rows={8}
                    value={replyText}
                    onChange={e => setReplyText(e.target.value)}
                    placeholder="Enter your professional response..."
                    className="w-full border-slate-200 border-2 rounded-2xl p-6 text-sm focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all outline-none"
                  ></textarea>
                  <div className="absolute bottom-4 right-4 flex gap-2">
                    <button 
                      onClick={handleSendReply}
                      disabled={!replyText}
                      className="px-8 py-3 rounded-xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all disabled:opacity-50 disabled:shadow-none"
                    >
                      Dispatch & Resolve
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Column: AI Sidebar & Audit Trail */}
        <div className="lg:col-span-4 space-y-6">
          {/* AI Intelligence Block */}
          <div className="bg-slate-900 rounded-3xl p-6 shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-3xl transition-all group-hover:scale-150"></div>
            <div className="relative z-10 space-y-6">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-lg bg-indigo-500 flex items-center justify-center text-white">
                    <i className="fas fa-brain text-sm"></i>
                  </div>
                  <h4 className="text-white font-bold text-sm">Enterprise Co-Pilot</h4>
                </div>
                {isAiLoading && <i className="fas fa-spinner fa-spin text-indigo-400"></i>}
              </div>

              {aiAnalysis ? (
                <div className="space-y-4">
                  <div className="bg-white/5 p-4 rounded-xl border border-white/10">
                    <p className="text-[9px] font-bold text-indigo-300 uppercase tracking-widest mb-2">Intent Summary</p>
                    <p className="text-xs text-slate-300 leading-relaxed italic">"{aiAnalysis.summary}"</p>
                  </div>

                  <div className="space-y-2">
                    <p className="text-[9px] font-bold text-indigo-300 uppercase tracking-widest">Recommended KB Articles</p>
                    <div className="flex flex-wrap gap-2">
                      {aiAnalysis.kbKeywords.map(kw => (
                        <span key={kw} className="bg-indigo-500/10 text-indigo-200 px-2 py-1 rounded text-[10px] font-medium border border-indigo-500/20 cursor-pointer hover:bg-indigo-500/20 transition-all">
                          <i className="fas fa-book-open mr-1.5 opacity-60"></i>{kw}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              ) : (
                <p className="text-xs text-slate-500 italic">Waiting for signal analysis...</p>
              )}
            </div>
          </div>

          {/* Audit Trail / Timeline */}
          <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm flex flex-col h-[400px]">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
              <i className="fas fa-timeline"></i> Activity & Audit Trail
            </h4>
            <div className="flex-1 overflow-y-auto pr-2 space-y-6 relative">
              <div className="absolute left-3.5 top-0 bottom-0 w-0.5 bg-slate-100"></div>
              {ticket.history.map((log, idx) => (
                <div key={log.id} className="relative pl-10">
                  <div className="absolute left-2.5 top-1.5 w-2.5 h-2.5 rounded-full bg-white border-2 border-indigo-500 z-10"></div>
                  <p className="text-xs font-bold text-slate-800">{log.action}</p>
                  <p className="text-[10px] text-slate-400 mt-0.5">{log.user} • {new Date(log.timestamp).toLocaleTimeString()}</p>
                </div>
              ))}
              <div className="relative pl-10 opacity-50">
                <div className="absolute left-2.5 top-1.5 w-2.5 h-2.5 rounded-full bg-slate-200 border-2 border-slate-300 z-10"></div>
                <p className="text-[10px] italic text-slate-400">End of records</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TicketDetail;

import React, { useState } from 'react';
import { Ticket, Channel, Category, Priority, Status, TicketHistory } from '../types';
import { processTicketWithRules } from '../services/aiService';

interface TicketFormProps {
  onSubmit: (ticket: Ticket) => void;
  onCancel: () => void;
}

const TicketForm: React.FC<TicketFormProps> = ({ onSubmit, onCancel }) => {
  const [formData, setFormData] = useState({
    customerName: '',
    customerEmail: '',
    channel: Channel.WEB_FORM,
    category: Category.TECHNICAL,
    subject: '',
    message: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const aiResult = processTicketWithRules(formData.message);

    // Industry SLA Logic: Urgent = 4h, High = 12h, Medium = 24h, Low = 48h
    const slaHours = aiResult.priority === Priority.URGENT ? 4 : 
                     aiResult.priority === Priority.HIGH ? 12 : 
                     aiResult.priority === Priority.MEDIUM ? 24 : 48;

    const deadline = new Date();
    deadline.setHours(deadline.getHours() + slaHours);

    const initialHistory: TicketHistory[] = [
      { id: Date.now().toString(), action: 'Ticket Created via System', timestamp: new Date().toISOString(), user: 'System Bot' },
      { id: (Date.now() + 1).toString(), action: `Auto-assigned Priority: ${aiResult.priority}`, timestamp: new Date().toISOString(), user: 'AI Engine' }
    ];

    const newTicket: Ticket = {
      ...formData,
      id: `T-${Math.floor(Math.random() * 90000) + 10000}`,
      status: Status.OPEN,
      priority: aiResult.priority,
      tags: aiResult.tags,
      slaDeadline: deadline.toISOString(),
      history: initialHistory,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    onSubmit(newTicket);
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="bg-indigo-600 p-10 text-white relative overflow-hidden">
