            <h2 className="text-3xl font-black tracking-tight">Enterprise Query Intake</h2>
            <p className="text-indigo-100 mt-2 font-medium opacity-80 max-w-md">Our AI Engine will real-time analyze sentiment, priority, and SLA routing for this request.</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-10 space-y-8">
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer Identity</label>
              <input 
                required
                type="text" 
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 focus:bg-white focus:border-indigo-500 transition-all outline-none font-medium"
                placeholder="Full Name"
                value={formData.customerName}
                onChange={e => setFormData({...formData, customerName: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Contact Channel</label>
              <input 
                required
                type="email" 
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 focus:bg-white focus:border-indigo-500 transition-all outline-none font-medium"
                placeholder="Email Address"
                value={formData.customerEmail}
                onChange={e => setFormData({...formData, customerEmail: e.target.value})}
              />
            </div>
          </div>

          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Origin Source</label>
              <select 
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 focus:bg-white focus:border-indigo-500 transition-all outline-none font-medium"
                value={formData.channel}
                onChange={e => setFormData({...formData, channel: e.target.value as Channel})}
              >
                {Object.values(Channel).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Classification</label>
              <select 
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 focus:bg-white focus:border-indigo-500 transition-all outline-none font-medium"
                value={formData.category}
