          <div className="text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">SLA Health Score</p>
            <p className={`text-xl font-black ${slaHealth > 90 ? 'text-emerald-500' : 'text-amber-500'}`}>{slaHealth}%</p>
          </div>
          <div className={`w-10 h-10 rounded-full border-4 ${slaHealth > 90 ? 'border-emerald-500' : 'border-amber-500'} flex items-center justify-center`}>
            <i className={`fas ${slaHealth > 90 ? 'fa-check' : 'fa-exclamation'} text-xs ${slaHealth > 90 ? 'text-emerald-500' : 'text-amber-500'}`}></i>
          </div>
        </div>
      </div>

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {/* Sentiment Analysis */}
        <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm h-[450px] flex flex-col">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Global Sentiment</h3>
            <i className="fas fa-face-smile text-indigo-400"></i>
          </div>
          <div className="flex-1">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={sentimentData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={90}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {sentimentData.map((entry) => (
                    <Cell key={`cell-${entry.name}`} fill={SENTIMENT_COLORS[entry.name]} stroke="none" />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Distribution */}
        <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm h-[450px] flex flex-col">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Workflow State</h3>
            <i className="fas fa-layer-group text-indigo-400"></i>
          </div>
          <div className="flex-1">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statusData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} className="text-[10px] font-bold" />
                <YAxis axisLine={false} tickLine={false} className="text-[10px] font-bold" />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="value" fill="#6366f1" radius={[10, 10, 0, 0]} barSize={45} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Channel Distribution */}
        <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm h-[450px] flex flex-col md:col-span-2 lg:col-span-1">
          <div className="flex justify-between items-center mb-8">
